const s = $input.first().json;
const d = new Date().toDateString();
const emoji = s.new_users > 0 ? '🎉' : '📊';
const body = `${emoji} *snspokes Daily Digest — ${d}*\n\n` +
  `👥 New users: ${s.new_users} (Total: ${s.total_users})\n` +
  `🔍 Searches: ${s.searches_today}\n` +
  `💻 Code generations: ${s.code_gens_today}\n` +
  `💰 Revenue today: ₹${s.revenue_today}\n` +
  `📦 Active subscriptions: ${s.active_subs}\n` +
  `⚠️ Open errors: ${s.open_errors}\n\n` +
  `View dashboard: ${process.env.APP_URL || 'http://77.42.71.149'}/admin/dashboard`;
return [{ json: { body, date: d, stats: s } }];
